// Category alone is not specific enough — only used as a tiebreaker
const categoryMap = {};

function fetch(url) {
  return new Promise((resolve, reject) => {
    https.get(url, { headers: { "User-Agent": "marcus-cyborg-graph/1.0" } }, (res) => {
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        return fetch(res.headers.location).then(resolve, reject);
      }
      if (res.statusCode !== 200) {
        return reject(new Error(`HTTP ${res.statusCode}`));
      }
      const chunks = [];
      res.on("data", (c) => chunks.push(c));
      res.on("end", () => resolve(Buffer.concat(chunks).toString()));
      res.on("error", reject);
    }).on("error", reject);
  });
}

function matchConcepts(article) {
  const matched = new Set();

  // Check exact tag matches
  const tags = (article.tags || []).map((t) => t.toLowerCase());
  for (const tag of tags) {
    if (exactTagMap[tag]) {
      exactTagMap[tag].forEach((c) => matched.add(c));
    }
  }

  // Check title keyword matches
  const title = (article.title || "").toLowerCase();
  for (const [keyword, conceptIds] of Object.entries(titleKeywordMap)) {
    if (title.includes(keyword)) {
      conceptIds.forEach((c) => matched.add(c));
    }
  }

  // Check category matches
  const cat = (article.category || "").toLowerCase();
  if (categoryMap[cat]) {
    categoryMap[cat].forEach((c) => matched.add(c));
  }

  return [...matched];
}

function truncate(str, len) {
  if (!str) return "";
  return str.length > len ? str.slice(0, len) + "…" : str;
}

// Max articles to show per concept (keeps graph readable)
const MAX_ARTICLES_PER_CONCEPT = 5;
// Max total article nodes in graph
const MAX_TOTAL_ARTICLES = 40;

async function main() {
  console.log("Fetching ontology data from GitHub...");
  const raw = await fetch(JSONL_URL);
  const lines = raw.split("\n").filter((l) => l.trim());

  console.log(`Parsing ${lines.length} JSONL entries...`);

  const articles = [];
  for (const line of lines) {
    try {
      const obj = JSON.parse(line);
      if (obj.entity && obj.entity.type === "Article") {
        const p = obj.entity.properties;
        articles.push({
          id: obj.entity.id,
          title: p.title,
          tags: p.tags || [],
          category: p.category || "",
          publication: p.publication || "",
          url: p.url || "",
        });
      }
    } catch (e) {
      // skip malformed lines
    }
  }

  console.log(`Found ${articles.length} articles.`);

  // First pass: match all articles to concepts and count connections
  const conceptConnectionCount = {};
  const articleMatches = []; // { article, conceptIds }

  for (const art of articles) {
    const conceptIds = matchConcepts(art);
    if (conceptIds.length === 0) continue;
    articleMatches.push({ article: art, conceptIds });
    for (const cid of conceptIds) {
      conceptConnectionCount[cid] = (conceptConnectionCount[cid] || 0) + 1;
    }
  }

  // Second pass: select representative articles per concept
  // Prefer articles that connect to multiple concepts (more interesting nodes)
  articleMatches.sort((a, b) => b.conceptIds.length - a.conceptIds.length);

  const selectedIds = new Set();
  const perConceptCount = {};

  // First: pick multi-concept articles (they create interesting cross-links)
  for (const m of articleMatches) {
    if (selectedIds.size >= MAX_TOTAL_ARTICLES) break;
    if (m.conceptIds.length >= 3) {
      selectedIds.add(m.article.id);
    }
  }

  // Then: fill each concept up to MAX_ARTICLES_PER_CONCEPT
  for (const m of articleMatches) {
    if (selectedIds.size >= MAX_TOTAL_ARTICLES) break;
    const needed = m.conceptIds.some((cid) => {
      return (perConceptCount[cid] || 0) < MAX_ARTICLES_PER_CONCEPT;
    });
    if (needed) {
      selectedIds.add(m.article.id);
      for (const cid of m.conceptIds) {
        perConceptCount[cid] = (perConceptCount[cid] || 0) + 1;
      }
    }
  }

  // Build selected article nodes and links
  const articleNodes = [];
  const articleLinks = [];

  for (const m of articleMatches) {
    if (!selectedIds.has(m.article.id)) continue;
    const art = m.article;
    const shortTitle = truncate(art.title, 40);
    articleNodes.push({
      id: art.id,
      name: shortTitle,
      type: "article",
      group: 3,
      size: 8 + Math.min(m.conceptIds.length * 3, 12),
      description: art.publication ? `${art.publication}` : "",
      url: art.url,
    });

    for (const cid of m.conceptIds) {
      articleLinks.push({ source: art.id, target: cid, type: "discusses" });
    }
  }

  // Build concept nodes with size based on TOTAL connection count (all articles)
  const conceptNodes = concepts.map((c) => ({
    ...c,
    type: "concept",
    group: 1,
    size: 20 + Math.min(Math.sqrt(conceptConnectionCount[c.id] || 0) * 3, 30),
    articleCount: conceptConnectionCount[c.id] || 0,
  }));

  // Build task nodes
  const taskNodes = tasks.map((t) => ({
    ...t,
    type: "task",
    group: 2,
    size: 18,
  }));

  // Find related articles (share 2+ concepts) — only among selected articles
  const relatedLinks = [];
  const artConceptMap = new Map();
  for (const m of articleMatches) {
    if (selectedIds.has(m.article.id)) {
      artConceptMap.set(m.article.id, new Set(m.conceptIds));
    }
  }
  const selectedArr = [...artConceptMap.keys()];
  for (let i = 0; i < selectedArr.length; i++) {
    const aConcepts = artConceptMap.get(selectedArr[i]);
    for (let j = i + 1; j < selectedArr.length; j++) {
      const bConcepts = artConceptMap.get(selectedArr[j]);
      let overlap = 0;
      for (const c of aConcepts) { if (bConcepts.has(c)) overlap++; }
      if (overlap >= 4) {
        relatedLinks.push({
          source: selectedArr[i],
          target: selectedArr[j],
          type: "related",
        });
      }
    }
  }

  const graphData = {
    generated: new Date().toISOString(),
    stats: {
      totalArticles: articles.length,
      matchedArticles: articleMatches.length,
      displayedArticles: articleNodes.length,
      concepts: concepts.length,
      tasks: tasks.length,
      links: articleLinks.length + taskConceptLinks.length + relatedLinks.length,
    },
    nodes: [...conceptNodes, ...taskNodes, ...articleNodes],
    links: [...taskConceptLinks, ...articleLinks, ...relatedLinks],
  };

  fs.writeFileSync(OUTPUT, JSON.stringify(graphData));
  console.log(`Graph data written to ${OUTPUT}`);
  console.log(`  ${conceptNodes.length} concepts, ${taskNodes.length} tasks, ${articleNodes.length}/${articleMatches.length} articles`);
  console.log(`  ${graphData.links.length} total links`);
  console.log(`  Concept coverage: ${conceptNodes.map(c => `${c.name}(${c.articleCount})`).join(', ')}`);
}

main().catch((err) => {
  console.error("Error:", err.message);
  process.exit(1);
});
